code = """import json
import pandas as pd

# Get file path
file_path = locals()['var_function-call-13009457087833223663']

# Load reviews
with open(file_path, 'r') as f:
    reviews = json.load(f)

# Create DataFrame
df_reviews = pd.DataFrame(reviews)
# Ensure rating is float
df_reviews['rating'] = df_reviews['rating'].astype(float)

# Calculate average rating
avg_ratings = df_reviews.groupby('purchase_id')['rating'].mean().reset_index()

# Filter for perfect rating 5.0
perfect_books = avg_ratings[avg_ratings['rating'] == 5.0]

# Get the list of perfect purchase_ids
perfect_p_ids = perfect_books['purchase_id'].tolist()

# Map back to book_id
perfect_b_ids = [pid.replace('purchaseid_', 'bookid_') for pid in perfect_p_ids]

# Load book info
books_info = locals()['var_function-call-908477051567661839']

# Find titles
result_titles = []
for book in books_info:
    if book['book_id'] in perfect_b_ids:
        result_titles.append(book['title'])

print("__RESULT__:")
print(json.dumps(result_titles))"""

